# BATCH 2: OCAP, File I/O, Network, DB combinations (80-130)
# ============================================================
{"instruction": "Lese eine JSON-Konfigurationsdatei, parse sie und gib einen bestimmten Wert aus.", "output": "agent JsonConfigReader {\n    public void ReadConfig(FileAccess fs) {\n        var raw = fs_read(\"config.json\")?;\n        var json = json_parse(raw)?;\n        var host = json_get(json, \"/server/host\");\n        var port = json_get_int(json, \"/server/port\");\n        print $\"Server: {host}:{port}\";\n    }\n\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                self.ReadConfig(fs);\n            } catch err {\n                print $\"Config error: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der eine Datei binaer liest und die Groesse in Bytes ausgibt.", "output": "agent BinaryReader {\n    public void CheckFile(string path, FileAccess fs) {\n        var size = fs_size(path)?;\n        var bytes = fs_read_bytes(path)?;\n        print $\"File {path}: {size} bytes, read {bytes.len()} bytes\";\n        print $\"First byte: {bytes[0]}\";\n    }\n\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                self.CheckFile(\"data.bin\", fs);\n            } catch err {\n                print $\"Error: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle eine SQLite-Datenbank mit mehreren Tabellen und Fremdschluessel.", "output": "agent SchemaBuilder {\n    public void Setup(DbAccess cap) {\n        var db = db_open(\"shop.db\");\n        db_execute(db, \"CREATE TABLE IF NOT EXISTS categories (id INTEGER PRIMARY KEY, name TEXT)\", []);\n        db_execute(db, \"CREATE TABLE IF NOT EXISTS products (id INTEGER PRIMARY KEY, name TEXT, category_id INTEGER, price REAL)\", []);\n        db_execute(db, \"INSERT INTO categories (name) VALUES (?1)\", [\"Electronics\"]);\n        db_execute(db, \"INSERT INTO products (name, category_id, price) VALUES (?1, ?2, ?3)\", [\"Laptop\", \"1\", \"999.99\"]);\n        var rows = db_query(db, \"SELECT p.name, c.name as category FROM products p JOIN categories c ON p.category_id = c.id\", []);\n        for row in rows {\n            print $\"{row[\"name\"]} in {row[\"category\"]}\";\n        }\n    }\n\n    public void Run() {\n        unsafe {\n            var cap = DbAccess {};\n            self.Setup(cap);\n        }\n    }\n}"},
{"instruction": "Sende einen HTTP POST Request mit JSON-Body und parse die Antwort.", "output": "agent ApiPoster {\n    public void PostData(NetworkAccess net) {\n        var body = \"{\\\"name\\\": \\\"Varg\\\", \\\"version\\\": \\\"0.10.0\\\"}\";\n        var headers = {\"Content-Type\": \"application/json\"};\n        var resp = http_request(\"https://httpbin.org/post\", \"POST\", headers, body)?;\n        var json = json_parse(resp)?;\n        var data = json_get(json, \"/data\");\n        print $\"Server received: {data}\";\n    }\n\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            try {\n                self.PostData(net);\n            } catch err {\n                print $\"POST failed: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Kombiniere FileAccess und NetworkAccess: Lade eine URL herunter, speichere sie, lies sie zurueck.", "output": "agent DownloadAndVerify {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var fs = FileAccess {};\n            try {\n                var html = fetch(\"https://example.com\", \"GET\")?;\n                fs_write(\"example.html\", html)?;\n                var read_back = fs_read(\"example.html\")?;\n                print $\"Downloaded {html.len()} bytes, verified {read_back.len()} bytes\";\n            } catch err {\n                log_error($\"Download failed: {err}\");\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle einen Agenten, der mehrere Dateien in einem Verzeichnis auflistet und deren Groessen summiert.", "output": "agent DiskUsage {\n    public void CalculateSize(string dir, FileAccess fs) {\n        var files = fs_read_dir(dir)?;\n        var total = 0;\n        for f in files {\n            var size = fs_size(f) or 0;\n            total = total + size;\n            print $\"{f}: {size} bytes\";\n        }\n        print $\"Total: {total} bytes\";\n    }\n\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                self.CalculateSize(\"./data\", fs);\n            } catch err {\n                print $\"Error: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der SQLite als Cache nutzt: prueft ob ein Key existiert, sonst fuegt er ihn ein.", "output": "agent CacheAgent {\n    public string GetOrSet(string key, string value, DbAccess cap) {\n        var db = db_open(\"cache.db\");\n        db_execute(db, \"CREATE TABLE IF NOT EXISTS cache (key TEXT PRIMARY KEY, value TEXT)\", []);\n        var rows = db_query(db, \"SELECT value FROM cache WHERE key = ?1\", [key]);\n        if rows.len() > 0 {\n            return rows[0][\"value\"];\n        }\n        db_execute(db, \"INSERT INTO cache (key, value) VALUES (?1, ?2)\", [key, value]);\n        return value;\n    }\n\n    public void Run() {\n        unsafe {\n            var cap = DbAccess {};\n            var result = self.GetOrSet(\"greeting\", \"Hello World\", cap);\n            print $\"Value: {result}\";\n        }\n    }\n}"},
{"instruction": "Erstelle einen HTTP Server mit mehreren Routen: GET, POST und DELETE.", "output": "agent CrudServer {\n    public async void Run() {\n        var server = http_serve();\n        http_route(server, \"GET\", \"/items\", (req) => {\n            return http_response(200, \"[{\\\"id\\\": 1, \\\"name\\\": \\\"Widget\\\"}]\");\n        });\n        http_route(server, \"POST\", \"/items\", (req) => {\n            print $\"Creating item: {req.body}\";\n            return http_response(201, \"{\\\"status\\\": \\\"created\\\"}\");\n        });\n        http_route(server, \"DELETE\", \"/items\", (req) => {\n            return http_response(200, \"{\\\"status\\\": \\\"deleted\\\"}\");\n        });\n        print \"CRUD server starting on :8080\";\n        http_listen(server, \"0.0.0.0:8080\");\n    }\n}"},
{"instruction": "Nutze retry mit backoff, um eine instabile API aufzurufen.", "output": "agent ResilientFetcher {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var result = retry(5, backoff: 2000) {\n                fetch(\"https://unstable-api.example.com/data\", \"GET\")?\n            } fallback {\n                \"{\\\"status\\\": \\\"cached\\\"}\"\n            };\n            print $\"Result: {result}\";\n        }\n    }\n}"},
{"instruction": "Schreibe binaere Daten in eine Datei und lese sie zurueck.", "output": "agent BinaryIO {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var bytes = [0, 1, 2, 255, 128, 64];\n            var written = fs_write_bytes(\"test.bin\", bytes) or 0;\n            print $\"Wrote {written} bytes\";\n            var read = fs_read_bytes(\"test.bin\") or [];\n            print $\"Read back {read.len()} bytes\";\n            for b in read {\n                print $\"Byte: {b}\";\n            }\n        }\n    }\n}"},
{"instruction": "Nutze fs_append, um eine Log-Datei zeilenweise zu erweitern.", "output": "agent FileAppender {\n    public void AppendLog(string msg, FileAccess fs) {\n        var timestamp = time_format(time_millis(), \"%Y-%m-%d %H:%M:%S\");\n        fs_append(\"agent.log\", $\"[{timestamp}] {msg}\\n\")?;\n    }\n\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                self.AppendLog(\"Agent started\", fs);\n                self.AppendLog(\"Processing data\", fs);\n                self.AppendLog(\"Agent finished\", fs);\n            } catch err {\n                log_error($\"Log append failed: {err}\");\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle ein Verzeichnis, schreibe Dateien hinein und liste den Inhalt auf.", "output": "agent DirectoryManager {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                create_dir(\"./output\")?;\n                fs_write(\"./output/file1.txt\", \"Hello\")?;\n                fs_write(\"./output/file2.txt\", \"World\")?;\n                var files = fs_read_dir(\"./output\")?;\n                print $\"Created {files.len()} files\";\n                for f in files {\n                    print f;\n                }\n            } catch err {\n                print $\"Error: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Nutze path_exists, um vor dem Lesen zu pruefen, ob eine Datei vorhanden ist.", "output": "agent SafeReader {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var path = \"config.toml\";\n            if path_exists(path) {\n                var content = fs_read(path) or \"\";\n                print $\"Config loaded: {content.len()} chars\";\n            } else {\n                print \"Config file not found, using defaults\";\n            }\n        }\n    }\n}"},
{"instruction": "Baue einen Agenten, der HTTP-Antworten in SQLite protokolliert.", "output": "agent HttpLogger {\n    public void LogResponse(string url, NetworkAccess net, DbAccess db_cap) {\n        var db = db_open(\"http_log.db\");\n        db_execute(db, \"CREATE TABLE IF NOT EXISTS logs (url TEXT, status TEXT, timestamp TEXT)\", []);\n        try {\n            var resp = fetch(url, \"GET\")?;\n            var ts = time_format(time_millis(), \"%Y-%m-%d %H:%M:%S\");\n            db_execute(db, \"INSERT INTO logs (url, status, timestamp) VALUES (?1, ?2, ?3)\", [url, \"ok\", ts]);\n        } catch err {\n            var ts = time_format(time_millis(), \"%Y-%m-%d %H:%M:%S\");\n            db_execute(db, \"INSERT INTO logs (url, status, timestamp) VALUES (?1, ?2, ?3)\", [url, $\"error: {err}\", ts]);\n        }\n    }\n\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var db_cap = DbAccess {};\n            self.LogResponse(\"https://api.github.com\", net, db_cap);\n        }\n    }\n}"},
{"instruction": "Erstelle einen Agenten, der die Plattform-Verzeichnisse (home, config, data, cache) ausgibt.", "output": "agent PlatformDirs {\n    public void Run() {\n        print $\"Home: {home_dir()}\";\n        print $\"Config: {config_dir()}\";\n        print $\"Data: {data_dir()}\";\n        print $\"Cache: {cache_dir()}\";\n    }\n}"},
{"instruction": "Nutze config_load_cascade, um Konfigurationen aus mehreren Dateien zu laden und zusammenzufuehren.", "output": "agent ConfigCascade {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                var config = config_load_cascade([\"defaults.json\", \"local.json\", \"override.json\"])?;\n                var json = json_parse(config)?;\n                var mode = json_get(json, \"/mode\");\n                print $\"Merged config mode: {mode}\";\n            } catch err {\n                print $\"Config load failed: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der Encrypt und Decrypt fuer einen Geheimtext demonstriert.", "output": "agent CryptoDemo {\n    public void Run() {\n        var plaintext = \"Geheime Nachricht\";\n        var key = \"my_secret_key_16\";\n        var encrypted = encrypt(plaintext, key);\n        print $\"Encrypted: {encrypted}\";\n        var decrypted = decrypt(encrypted, key);\n        print $\"Decrypted: {decrypted}\";\n    }\n}"},
{"instruction": "Kombiniere drei OCAP-Tokens in einem Agenten: FileAccess, NetworkAccess und DbAccess.", "output": "agent TripleCapAgent {\n    public void ProcessData(FileAccess fs, NetworkAccess net, DbAccess db_cap) {\n        var raw = fs_read(\"input.json\")?;\n        var enriched = fetch(\"https://api.example.com/enrich\", \"POST\") or raw;\n        var db = db_open(\"results.db\");\n        db_execute(db, \"CREATE TABLE IF NOT EXISTS data (payload TEXT)\", []);\n        db_execute(db, \"INSERT INTO data (payload) VALUES (?1)\", [enriched]);\n    }\n\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var net = NetworkAccess {};\n            var db_cap = DbAccess {};\n            try {\n                self.ProcessData(fs, net, db_cap);\n            } catch err {\n                log_error($\"Pipeline failed: {err}\");\n            }\n        }\n    }\n}"},
{"instruction": "Schreibe einen HTTP-Server, der Query-Parameter liest und zurueckgibt.", "output": "agent QueryServer {\n    public async void Run() {\n        var server = http_serve();\n        http_route(server, \"GET\", \"/search\", (req) => {\n            var query = req.query_params[\"q\"] or \"\";\n            return http_response(200, $\"{\\\"query\\\": \\\"{query}\\\"}\");\n        });\n        http_listen(server, \"0.0.0.0:3000\");\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der einen Base64-String kodiert und dekodiert.", "output": "agent Base64Demo {\n    public void Run() {\n        var original = \"Varg ist schnell!\";\n        var encoded = base64_encode(original);\n        print $\"Encoded: {encoded}\";\n        var decoded = base64_decode(encoded) or \"error\";\n        print $\"Decoded: {decoded}\";\n    }\n}"},
# ============================================================
# BATCH 3: Knowledge Graph, Vector Store, Memory (130-170)
# ============================================================
{"instruction": "Erstelle einen Knowledge Graph mit mehreren Knotentypen und verschiedenen Kantentypen.", "output": "agent MultiTypeGraph {\n    public void Run() {\n        var g = __varg_graph_open(\"company_graph\");\n        var alice = __varg_graph_add_node(g, \"Employee\", {\"name\": \"Alice\", \"role\": \"Engineer\"});\n        var bob = __varg_graph_add_node(g, \"Employee\", {\"name\": \"Bob\", \"role\": \"Manager\"});\n        var proj = __varg_graph_add_node(g, \"Project\", {\"name\": \"Varg Compiler\"});\n        __varg_graph_add_edge(g, alice, \"works_on\", proj, {\"since\": \"2024\"});\n        __varg_graph_add_edge(g, bob, \"manages\", proj, {});\n        __varg_graph_add_edge(g, bob, \"supervises\", alice, {});\n        var projects = __varg_graph_query(g, \"Project\");\n        print $\"Projects: {projects.len()}\";\n    }\n}"},
{"instruction": "Traversiere einen Knowledge Graph in der Tiefe und sammle alle erreichbaren Knoten.", "output": "agent GraphTraversal {\n    public void Run() {\n        var g = __varg_graph_open(\"social\");\n        var a = __varg_graph_add_node(g, \"Person\", {\"name\": \"Alice\"});\n        var b = __varg_graph_add_node(g, \"Person\", {\"name\": \"Bob\"});\n        var c = __varg_graph_add_node(g, \"Person\", {\"name\": \"Charlie\"});\n        var d = __varg_graph_add_node(g, \"Person\", {\"name\": \"Diana\"});\n        __varg_graph_add_edge(g, a, \"knows\", b, {});\n        __varg_graph_add_edge(g, b, \"knows\", c, {});\n        __varg_graph_add_edge(g, c, \"knows\", d, {});\n        var reachable = __varg_graph_traverse(g, a, 3, \"knows\");\n        print $\"Reachable from Alice: {reachable.len()} nodes\";\n    }\n}"},
{"instruction": "Speichere mehrere Dokumente im Vector Store und suche nach dem aehnlichsten.", "output": "agent SemanticSearch {\n    public void Run() {\n        unsafe {\n            var llm = LlmAccess {};\n            var store = __varg_vector_store_open(\"docs\");\n            var docs = [\"Varg is a compiled language\", \"Rust provides memory safety\", \"Python is interpreted\"];\n            for i in 0..docs.len() {\n                var emb = __varg_embed(docs[i]);\n                __varg_vector_store_upsert(store, $\"doc_{i}\", emb, {\"text\": docs[i]});\n            }\n            var query_emb = __varg_embed(\"Which language compiles to native code?\");\n            var results = __varg_vector_store_search(store, query_emb, 1);\n            print $\"Best match: {results[0][\"id\"]}\";\n        }\n    }\n}"},
{"instruction": "Loesche ein Dokument aus dem Vector Store und pruefe die Anzahl.", "output": "agent VectorDelete {\n    public void Run() {\n        unsafe {\n            var llm = LlmAccess {};\n            var store = __varg_vector_store_open(\"temp_store\");\n            var emb = __varg_embed(\"test document\");\n            __varg_vector_store_upsert(store, \"to_delete\", emb, {});\n            print $\"Before: {__varg_vector_store_count(store)}\";\n            __varg_vector_store_delete(store, \"to_delete\");\n            print $\"After: {__varg_vector_store_count(store)}\";\n        }\n    }\n}"},
{"instruction": "Nutze alle drei Schichten des Agent Memory: Working, Episodic und Semantic.", "output": "agent FullMemory {\n    public void Run() {\n        var mem = __varg_memory_open(\"assistant\");\n\n        // Working memory (Key-Value)\n        __varg_memory_set(mem, \"user_name\", \"Alice\");\n        __varg_memory_set(mem, \"session_id\", \"abc123\");\n        var name = __varg_memory_get(mem, \"user_name\", \"unknown\");\n        print $\"Working: {name}\";\n\n        // Episodic memory (Vector-based)\n        __varg_memory_store(mem, \"User asked about Varg syntax\", {\"topic\": \"syntax\"});\n        __varg_memory_store(mem, \"User debugged a parser error\", {\"topic\": \"debugging\"});\n        var episodes = __varg_memory_recall(mem, \"Varg syntax help\", 1);\n\n        // Semantic memory (Graph-based)\n        __varg_memory_add_fact(mem, \"User\", {\"name\": \"Alice\", \"expertise\": \"Rust\"});\n        var facts = __varg_memory_query_facts(mem, \"User\");\n\n        __varg_memory_clear_working(mem);\n    }\n}"},
{"instruction": "Kombiniere Knowledge Graph und Agent Memory, um Fakten zu speichern und abzufragen.", "output": "agent GraphMemoryAgent {\n    public void Run() {\n        var mem = __varg_memory_open(\"knowledge_bot\");\n        __varg_memory_add_fact(mem, \"Language\", {\"name\": \"Varg\", \"paradigm\": \"compiled\"});\n        __varg_memory_add_fact(mem, \"Language\", {\"name\": \"Python\", \"paradigm\": \"interpreted\"});\n        __varg_memory_add_fact(mem, \"Language\", {\"name\": \"Rust\", \"paradigm\": \"compiled\"});\n        var compiled = __varg_memory_query_facts(mem, \"Language\");\n        for fact in compiled {\n            print $\"Language fact found\";\n        }\n    }\n}"},
{"instruction": "Baue einen RAG-Agenten: Lade Dokumente, embedde sie, suche semantisch und generiere eine Antwort.", "output": "agent RagAgent {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var llm = LlmAccess {};\n            var store = __varg_vector_store_open(\"rag_store\");\n            var files = fs_read_dir(\"./docs\") or [];\n            for f in files {\n                var content = fs_read(f) or \"\";\n                if !content.is_empty() {\n                    var emb = __varg_embed(content);\n                    __varg_vector_store_upsert(store, f, emb, {\"source\": f});\n                }\n            }\n            var query = \"How does OCAP work?\";\n            var query_emb = __varg_embed(query);\n            var matches = __varg_vector_store_search(store, query_emb, 3);\n            print $\"Found {matches.len()} relevant documents\";\n        }\n    }\n}"},
{"instruction": "Nutze den cosine_sim Builtin direkt, um zwei Embeddings zu vergleichen.", "output": "agent SimilarityDemo {\n    public void Run() {\n        unsafe {\n            var llm = LlmAccess {};\n            var emb1 = __varg_embed(\"Varg is a compiled language\");\n            var emb2 = __varg_embed(\"Varg compiles to Rust\");\n            var emb3 = __varg_embed(\"I like pizza\");\n            var sim_close = cosine_sim(emb1, emb2);\n            var sim_far = cosine_sim(emb1, emb3);\n            print $\"Similar: {sim_close}\";\n            print $\"Different: {sim_far}\";\n        }\n    }\n}"},
# ============================================================
# BATCH 4: Tracing, Pipelines, Orchestration, Self-Improve (170-210)
# ============================================================
{"instruction": "Nutze Tracing, um mehrere verschachtelte Spans zu erzeugen und zu exportieren.", "output": "agent NestedTracing {\n    public void Run() {\n        var tracer = __varg_trace_start(\"app\");\n        var outer = __varg_trace_span(tracer, \"request_handler\");\n        __varg_trace_set_attr(tracer, \"method\", \"GET\");\n        var inner = __varg_trace_span(tracer, \"db_query\");\n        __varg_trace_set_attr(tracer, \"table\", \"users\");\n        __varg_trace_event(tracer, \"query_executed\", {\"rows\": \"42\"});\n        __varg_trace_end(tracer, inner);\n        __varg_trace_event(tracer, \"response_sent\", {\"status\": \"200\"});\n        __varg_trace_end(tracer, outer);\n        var json = __varg_trace_export(tracer);\n        print json;\n    }\n}"},
{"instruction": "Baue eine mehrstufige Pipeline, die Text normalisiert, tokenisiert und zaehlt.", "output": "agent TextPipeline {\n    public void Run() {\n        var pipe = __varg_pipeline_new(\"text_processor\");\n        __varg_pipeline_add_step(pipe, \"normalize\", (input) => input.trim().to_lower());\n        __varg_pipeline_add_step(pipe, \"remove_punct\", (input) => input.replace(\".\", \"\").replace(\",\", \"\"));\n        __varg_pipeline_add_step(pipe, \"count_words\", (input) => {\n            var words = input.split(\" \");\n            return $\"{words.len()} words\";\n        });\n        var result = __varg_pipeline_run(pipe, \"  Hello, World. This is Varg.  \");\n        print $\"Result: {result}\";\n    }\n}"},
{"instruction": "Nutze den Event Bus mit mehreren Event-Typen und verschiedenen Handlern.", "output": "agent MultiEventBus {\n    public void Run() {\n        var bus = __varg_event_bus_new(\"app\");\n        __varg_event_on(bus, \"user_login\", (data) => {\n            print $\"User logged in: {data[\"name\"]}\";\n            return \"ok\";\n        });\n        __varg_event_on(bus, \"user_logout\", (data) => {\n            print $\"User logged out: {data[\"name\"]}\";\n            return \"ok\";\n        });\n        __varg_event_on(bus, \"error\", (data) => {\n            log_error($\"Error: {data[\"msg\"]}\");\n            return \"logged\";\n        });\n        __varg_event_emit(bus, \"user_login\", {\"name\": \"Alice\"});\n        __varg_event_emit(bus, \"error\", {\"msg\": \"DB timeout\"});\n        __varg_event_emit(bus, \"user_logout\", {\"name\": \"Alice\"});\n    }\n}"},
{"instruction": "Nutze den Orchestrator, um vier Tasks parallel auszufuehren und die Ergebnisse zu aggregieren.", "output": "agent TaskAggregator {\n    public void Run() {\n        var orch = __varg_orchestrator_new(\"batch_job\");\n        __varg_orchestrator_add_task(orch, \"upper\", \"hello\");\n        __varg_orchestrator_add_task(orch, \"reverse\", \"world\");\n        __varg_orchestrator_add_task(orch, \"repeat\", \"ab\");\n        __varg_orchestrator_add_task(orch, \"length\", \"varg compiler\");\n        __varg_orchestrator_run_all(orch, (input) => {\n            return $\"{input} -> processed\";\n        });\n        var results = __varg_orchestrator_results(orch);\n        for r in results {\n            print $\"Task {r[\"id\"]}: {r[\"result\"]}\";\n        }\n    }\n}"},
{"instruction": "Nutze den Self-Improver, um aus vergangenen Erfahrungen die beste Strategie fuer eine Aufgabe zu finden.", "output": "agent AdaptiveAgent {\n    public void Run() {\n        var si = __varg_self_improver_new(\"code_agent\", 20);\n        __varg_self_improver_record_success(si, \"Parse JSON\", \"Used json_parse with error handling\");\n        __varg_self_improver_record_success(si, \"Read file\", \"Used fs_read with or fallback\");\n        __varg_self_improver_record_failure(si, \"HTTP call\", \"Forgot NetworkAccess capability\");\n        __varg_self_improver_record_failure(si, \"DB query\", \"Missing table creation\");\n        var tips = __varg_self_improver_recall(si, \"HTTP request\", 2);\n        var stats = __varg_self_improver_stats(si);\n        print $\"Success rate: {stats[\"success_rate\"]}\";\n    }\n}"},
{"instruction": "Kombiniere Tracing mit einer Pipeline: trace jeden Pipeline-Schritt.", "output": "agent TracedPipeline {\n    public void Run() {\n        var tracer = __varg_trace_start(\"pipeline_agent\");\n        var pipe = __varg_pipeline_new(\"traced_pipe\");\n        __varg_pipeline_add_step(pipe, \"step1\", (input) => {\n            var span = __varg_trace_span(tracer, \"step1\");\n            var result = input.to_upper();\n            __varg_trace_end(tracer, span);\n            return result;\n        });\n        __varg_pipeline_add_step(pipe, \"step2\", (input) => {\n            var span = __varg_trace_span(tracer, \"step2\");\n            var result = input.reverse();\n            __varg_trace_end(tracer, span);\n            return result;\n        });\n        var output = __varg_pipeline_run(pipe, \"hello\");\n        print $\"Output: {output}\";\n        print __varg_trace_export(tracer);\n    }\n}"},
{"instruction": "Kombiniere Event Bus mit Self-Improver: bewerte Events automatisch.", "output": "agent EventLearner {\n    public void Run() {\n        var si = __varg_self_improver_new(\"event_learner\", 10);\n        var bus = __varg_event_bus_new(\"learning_bus\");\n        __varg_event_on(bus, \"task_success\", (data) => {\n            __varg_self_improver_record_success(si, data[\"task\"], data[\"method\"]);\n            return \"recorded\";\n        });\n        __varg_event_on(bus, \"task_failure\", (data) => {\n            __varg_self_improver_record_failure(si, data[\"task\"], data[\"reason\"]);\n            return \"recorded\";\n        });\n        __varg_event_emit(bus, \"task_success\", {\"task\": \"compile\", \"method\": \"Used vargc build\"});\n        __varg_event_emit(bus, \"task_failure\", {\"task\": \"deploy\", \"reason\": \"Missing config\"});\n    }\n}"},
{"instruction": "Trace einen HTTP-Aufruf mit Error-Handling und exportiere das Ergebnis als JSON.", "output": "agent HttpTracer {\n    public void Run() {\n        var tracer = __varg_trace_start(\"http_agent\");\n        var span = __varg_trace_span(tracer, \"api_call\");\n        unsafe {\n            var net = NetworkAccess {};\n            try {\n                var start = time_millis();\n                var resp = fetch(\"https://httpbin.org/get\", \"GET\")?;\n                var duration = time_millis() - start;\n                __varg_trace_set_attr(tracer, \"duration_ms\", $\"{duration}\");\n                __varg_trace_set_attr(tracer, \"status\", \"ok\");\n                __varg_trace_event(tracer, \"response_received\", {\"bytes\": $\"{resp.len()}\"});\n            } catch err {\n                __varg_trace_error(tracer, $\"API error: {err}\");\n            }\n        }\n        __varg_trace_end(tracer, span);\n        print __varg_trace_export(tracer);\n    }\n}"},
# ============================================================
# BATCH 5: MCP, Actor model, WebSocket, SSE (210-260)
# ============================================================
{"instruction": "Erstelle einen MCP Server, der zwei Werkzeuge anbietet: string_length und string_upper.", "output": "agent TwoToolMcpServer {\n    public void Run() {\n        unsafe {\n            var sys = SystemAccess {};\n            var server = __varg_mcp_server_new(\"string_utils\", \"1.0.0\");\n            __varg_mcp_server_register(server, \"string_length\", \"Returns the length of a string\", (args) => {\n                var text = json_get(args, \"/text\");\n                return $\"{text.len()}\";\n            });\n            __varg_mcp_server_register(server, \"string_upper\", \"Converts a string to uppercase\", (args) => {\n                var text = json_get(args, \"/text\");\n                return text.to_upper();\n            });\n            __varg_mcp_server_run(server);\n        }\n    }\n}"},
{"instruction": "Verbinde dich mit einem MCP Server und rufe mehrere Tools nacheinander auf.", "output": "agent McpPipeline {\n    public void Run() {\n        unsafe {\n            var sys = SystemAccess {};\n            var conn = mcp_connect(\"npx\", [\"-y\", \"@modelcontextprotocol/server-everything\"]);\n            var tools = mcp_list_tools(conn);\n            print $\"Available tools: {tools.len()}\";\n            var r1 = mcp_call_tool(conn, \"echo\", {\"message\": \"step1\"});\n            var r2 = mcp_call_tool(conn, \"echo\", {\"message\": \"step2\"});\n            print $\"Step1: {r1}\";\n            print $\"Step2: {r2}\";\n            mcp_disconnect(conn);\n        }\n    }\n}"},
{"instruction": "Implementiere ein Actor-System mit einem Dispatcher, der Aufgaben an Worker verteilt.", "output": "agent Worker {\n    public void on_message(string msg, string[] args) {\n        match msg {\n            \"compute\" => {\n                var n = parse_int(args[0]) or 0;\n                print $\"Worker computed: {n * n}\";\n            }\n            _ => {\n                print $\"Unknown: {msg}\";\n            }\n        }\n    }\n}\n\nagent Dispatcher {\n    public void Run() {\n        var w1 = spawn Worker {};\n        var w2 = spawn Worker {};\n        w1.send(\"compute\", [\"5\"]);\n        w2.send(\"compute\", [\"7\"]);\n    }\n}"},
{"instruction": "Nutze request/reply im Actor-Modell, um synchron auf eine Antwort zu warten.", "output": "agent Calculator {\n    public void on_message(string msg, string[] args) {\n        if msg == \"add\" {\n            var a = parse_int(args[0]) or 0;\n            var b = parse_int(args[1]) or 0;\n            print $\"{a + b}\";\n        }\n    }\n}\n\nagent Client {\n    public void Run() {\n        var calc = spawn Calculator {};\n        var result = calc.request(\"add\", [\"10\", \"32\"]);\n        print $\"Result: {result}\";\n    }\n}"},
{"instruction": "Erstelle einen WebSocket-Client, der periodisch Heartbeats sendet.", "output": "agent HeartbeatClient {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var ws = ws_connect(\"ws://localhost:8080/ws\");\n            for i in 0..5 {\n                ws_send(ws, $\"{\\\"type\\\": \\\"heartbeat\\\", \\\"seq\\\": {i}}\");\n                var resp = ws_receive(ws);\n                print $\"Response: {resp}\";\n            }\n            ws_close(ws);\n        }\n    }\n}"},
{"instruction": "Baue einen WebSocket-Client, der JSON-Nachrichten empfaengt und den Typ dispatcht.", "output": "agent WsDispatcher {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var ws = ws_connect(\"ws://localhost:9000/events\");\n            var running = true;\n            while running {\n                var msg = ws_receive(ws);\n                var json = json_parse(msg) or \"{}\";\n                var event_type = json_get(json, \"/type\");\n                match event_type {\n                    \"update\" => {\n                        print $\"Update: {json_get(json, \"/data\")}\";\n                    }\n                    \"error\" => {\n                        log_error($\"WS Error: {json_get(json, \"/message\")}\");\n                    }\n                    \"close\" => {\n                        running = false;\n                    }\n                    _ => {\n                        log_warn($\"Unknown event: {event_type}\");\n                    }\n                }\n            }\n            ws_close(ws);\n        }\n    }\n}"},
{"instruction": "Nutze SSE, um einen Datenstrom von Tokens zu senden.", "output": "agent TokenStreamer {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var writer = sse_stream();\n            var tokens = [\"Hello\", \" \", \"World\", \"!\"];\n            for token in tokens {\n                sse_send(writer, \"token\", token);\n            }\n            sse_send(writer, \"done\", \"\");\n            sse_close(writer);\n        }\n    }\n}"},
{"instruction": "Spawne einen Prozess und warte auf dessen Beendigung.", "output": "agent ProcessManager {\n    public void Run() {\n        unsafe {\n            var sys = SystemAccess {};\n            var proc = proc_spawn(\"echo\", [\"Hello from child process\"]);\n            var exit_code = proc_wait(proc);\n            print $\"Process exited with: {exit_code}\";\n        }\n    }\n}"},
{"instruction": "Erstelle einen Readline-basierten REPL-Loop.", "output": "agent SimpleRepl {\n    public void Run() {\n        unsafe {\n            var sys = SystemAccess {};\n            var fs = FileAccess {};\n            var rl = readline_new() or \"error\";\n            print \"Varg REPL. Type :quit to exit.\";\n            while true {\n                try {\n                    var input = readline_read(rl, \"> \")?;\n                    if input == \":quit\" {\n                        break;\n                    }\n                    readline_add_history(rl, input)?;\n                    print $\"You said: {input}\";\n                } catch err {\n                    if err == \"eof\" {\n                        break;\n                    }\n                    print $\"Error: {err}\";\n                }\n            }\n            readline_save_history(rl, \".repl_history\")?;\n        }\n    }\n}"},
# ============================================================
# BATCH 6: Test framework, DI, complex patterns (260-310)
# ============================================================
{"instruction": "Schreibe eine umfangreiche Test-Suite mit BeforeEach, AfterEach und mehreren Assertions.", "output": "agent FullTestSuite {\n    string temp_file;\n\n    @[BeforeEach]\n    public void setup() {\n        temp_file = \"test_temp.txt\";\n    }\n\n    @[AfterEach]\n    public void teardown() {\n        unsafe {\n            var fs = FileAccess {};\n            delete_file(temp_file)?;\n        }\n    }\n\n    @[Test]\n    public void test_string_operations() {\n        assert_eq(\"hello\".to_upper(), \"HELLO\");\n        assert_contains(\"varg lang\", \"varg\");\n        assert_true(\"abc\".starts_with(\"a\"));\n        assert_false(\"\".len() > 0);\n    }\n\n    @[Test]\n    public void test_array_operations() {\n        var arr = [3, 1, 2];\n        arr.sort();\n        assert_eq(arr[0], 1);\n        assert_eq(arr.len(), 3);\n    }\n\n    @[Test]\n    public void test_math() {\n        assert_eq(abs(-42), 42);\n        assert_eq(min(3, 7), 3);\n        assert_eq(max(3, 7), 7);\n    }\n}"},
{"instruction": "Nutze assert_throws in einem Test, um zu pruefen, dass ein Fehler geworfen wird.", "output": "fn validate_email(string email) -> string {\n    if !email.contains(\"@\") {\n        throw \"Invalid email: missing @\";\n    }\n    return email;\n}\n\nagent ValidationTests {\n    @[Test]\n    public void test_valid_email() {\n        var result = validate_email(\"user@example.com\");\n        assert_eq(result, \"user@example.com\");\n    }\n\n    @[Test]\n    public void test_invalid_email() {\n        assert_throws(() => validate_email(\"no-at-sign\"));\n    }\n}"},
{"instruction": "Implementiere einen Contract fuer einen HTTP-Client und teste ihn mit einem Mock.", "output": "contract IHttpClient {\n    fn get(url: string) -> string;\n}\n\nagent RealHttpClient implements IHttpClient {\n    public string get(string url) {\n        unsafe {\n            var net = NetworkAccess {};\n            return fetch(url, \"GET\")?;\n        }\n    }\n}\n\nagent MockHttpClient implements IHttpClient {\n    public string get(string url) {\n        return \"{\\\"mocked\\\": true}\";\n    }\n}\n\nagent ApiService {\n    IHttpClient client;\n\n    public ApiService(IHttpClient client) {\n        self.client = client;\n    }\n\n    public string FetchData(string endpoint) {\n        return self.client.get(endpoint);\n    }\n}\n\nagent ApiTests {\n    @[Test]\n    public void test_with_mock() {\n        var mock = MockHttpClient {};\n        var service = ApiService { client: mock };\n        var result = service.FetchData(\"https://api.test.com\");\n        assert_contains(result, \"mocked\");\n    }\n}"},
{"instruction": "Erstelle einen Agenten, der Generics nutzt, um eine typsichere Stack-Datenstruktur zu implementieren.", "output": "struct Stack<T> {\n    T[] items;\n}\n\nimpl Stack<T> {\n    public fn push(T item) {\n        self.items.push(item);\n    }\n\n    public fn pop() -> T {\n        return self.items.pop();\n    }\n\n    public fn is_empty() -> bool {\n        return self.items.is_empty();\n    }\n\n    public fn size() -> int {\n        return self.items.len();\n    }\n}\n\nagent StackDemo {\n    public void Run() {\n        var stack = Stack { items: [] };\n        stack.push(\"first\");\n        stack.push(\"second\");\n        stack.push(\"third\");\n        print $\"Size: {stack.size()}\";\n        print $\"Pop: {stack.pop()}\";\n    }\n}"},
{"instruction": "Implementiere einen Contract fuer einen Key-Value Store mit zwei Backends: Memory und SQLite.", "output": "contract IKeyValueStore {\n    fn get(key: string) -> string;\n    fn set(key: string, value: string) -> void;\n}\n\nagent MemoryStore implements IKeyValueStore {\n    map<string, string> data;\n\n    public string get(string key) {\n        return self.data[key] or \"\";\n    }\n\n    public void set(string key, string value) {\n        self.data[key] = value;\n    }\n}\n\nagent SqliteStore implements IKeyValueStore {\n    public string get(string key) {\n        unsafe {\n            var cap = DbAccess {};\n            var db = db_open(\"kv.db\");\n            var rows = db_query(db, \"SELECT value FROM kv WHERE key = ?1\", [key]);\n            if rows.len() > 0 {\n                return rows[0][\"value\"];\n            }\n            return \"\";\n        }\n    }\n\n    public void set(string key, string value) {\n        unsafe {\n            var cap = DbAccess {};\n            var db = db_open(\"kv.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS kv (key TEXT PRIMARY KEY, value TEXT)\", []);\n            db_execute(db, \"INSERT OR REPLACE INTO kv (key, value) VALUES (?1, ?2)\", [key, value]);\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der eine CSV-Datei parst und die Spalten als Map zurueckgibt.", "output": "agent CsvParser {\n    public void Parse(string path, FileAccess fs) {\n        var lines = fs_read_lines(path)?;\n        if lines.is_empty() {\n            throw \"CSV file is empty\";\n        }\n        var headers = lines[0].split(\",\");\n        for i in 1..lines.len() {\n            var values = lines[i].split(\",\");\n            for j in 0..headers.len() {\n                if j < values.len() {\n                    print $\"{headers[j].trim()}: {values[j].trim()}\";\n                }\n            }\n            print \"---\";\n        }\n    }\n\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            try {\n                self.Parse(\"data.csv\", fs);\n            } catch err {\n                print $\"CSV parse error: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle eine Test-Suite, die File I/O testet und dabei das Filesystem aufraumt.", "output": "agent FileTests {\n    string test_path;\n\n    @[BeforeEach]\n    public void setup() {\n        test_path = \"test_output.txt\";\n    }\n\n    @[AfterEach]\n    public void cleanup() {\n        unsafe {\n            var fs = FileAccess {};\n            if path_exists(test_path) {\n                delete_file(test_path)?;\n            }\n        }\n    }\n\n    @[Test]\n    public void test_write_and_read() {\n        unsafe {\n            var fs = FileAccess {};\n            fs_write(test_path, \"hello\")?;\n            var content = fs_read(test_path)?;\n            assert_eq(content, \"hello\");\n        }\n    }\n\n    @[Test]\n    public void test_append() {\n        unsafe {\n            var fs = FileAccess {};\n            fs_write(test_path, \"line1\\n\")?;\n            fs_append(test_path, \"line2\\n\")?;\n            var lines = fs_read_lines(test_path)?;\n            assert_eq(lines.len(), 2);\n        }\n    }\n}"},
{"instruction": "Nutze Pattern Matching mit einem Enum, um HTTP-Statuscodes zu klassifizieren.", "output": "enum HttpStatus {\n    Ok,\n    NotFound,\n    ServerError,\n    Unknown(int)\n}\n\nfn classify_status(int code) -> HttpStatus {\n    match code {\n        200 => { return HttpStatus.Ok; }\n        404 => { return HttpStatus.NotFound; }\n        500 => { return HttpStatus.ServerError; }\n        _ => { return HttpStatus.Unknown(code); }\n    }\n}\n\nagent StatusClassifier {\n    public void Run() {\n        var codes = [200, 404, 500, 301];\n        for c in codes {\n            var status = classify_status(c);\n            match status {\n                HttpStatus.Ok => { print \"OK\"; }\n                HttpStatus.NotFound => { print \"Not Found\"; }\n                HttpStatus.ServerError => { print \"Server Error\"; }\n                HttpStatus.Unknown(n) => { print $\"Unknown: {n}\"; }\n            }\n        }\n    }\n}"},
