{"instruction": "Baue einen HTTP-Server, der Anfragen traced und in SQLite protokolliert.", "output": "agent TracedApiServer {\n    public async void Run() {\n        var tracer = __varg_trace_start(\"api_server\");\n        unsafe {\n            var db_cap = DbAccess {};\n            var db = db_open(\"requests.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS requests (method TEXT, path TEXT, timestamp TEXT)\", []);\n            var server = http_serve();\n            http_route(server, \"GET\", \"/api/data\", (req) => {\n                var span = __varg_trace_span(tracer, \"handle_get_data\");\n                var ts = time_format(time_millis(), \"%Y-%m-%d %H:%M:%S\");\n                db_execute(db, \"INSERT INTO requests (method, path, timestamp) VALUES (?1, ?2, ?3)\", [\"GET\", \"/api/data\", ts]);\n                __varg_trace_end(tracer, span);\n                return http_response(200, \"{\\\"data\\\": \\\"ok\\\"}\");\n            });\n            http_listen(server, \"0.0.0.0:8080\");\n        }\n    }\n}"},
{"instruction": "Kombiniere Knowledge Graph, Vector Store und Memory fuer einen intelligenten Agenten.", "output": "agent IntelligentAgent {\n    public void Run() {\n        unsafe {\n            var llm = LlmAccess {};\n            var mem = __varg_memory_open(\"smart_bot\");\n            var store = __varg_vector_store_open(\"knowledge\");\n            var g = __varg_graph_open(\"concepts\");\n\n            // Add knowledge\n            var varg_node = __varg_graph_add_node(g, \"Language\", {\"name\": \"Varg\"});\n            var rust_node = __varg_graph_add_node(g, \"Language\", {\"name\": \"Rust\"});\n            __varg_graph_add_edge(g, varg_node, \"compiles_to\", rust_node, {});\n\n            // Embed and store\n            var emb = __varg_embed(\"Varg compiles to Rust for native performance\");\n            __varg_vector_store_upsert(store, \"varg_intro\", emb, {\"source\": \"docs\"});\n\n            // Working memory\n            __varg_memory_set(mem, \"current_topic\", \"language_comparison\");\n\n            // Query\n            var neighbors = __varg_graph_neighbors(g, varg_node);\n            var search = __varg_vector_store_search(store, emb, 1);\n            print $\"Graph neighbors: {neighbors.len()}, Vector results: {search.len()}\";\n        }\n    }\n}"},
{"instruction": "Implementiere einen Chat-Server mit WebSocket und SQLite-Message-History.", "output": "agent ChatServer {\n    public async void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var db_cap = DbAccess {};\n            var db = db_open(\"chat.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS messages (sender TEXT, text TEXT, timestamp TEXT)\", []);\n            var server = http_serve();\n            http_route(server, \"POST\", \"/send\", (req) => {\n                var json = json_parse(req.body) or \"{}\";\n                var sender = json_get(json, \"/sender\");\n                var text = json_get(json, \"/text\");\n                var ts = time_format(time_millis(), \"%H:%M:%S\");\n                db_execute(db, \"INSERT INTO messages (sender, text, timestamp) VALUES (?1, ?2, ?3)\", [sender, text, ts]);\n                return http_response(200, \"{\\\"status\\\": \\\"sent\\\"}\");\n            });\n            http_route(server, \"GET\", \"/history\", (req) => {\n                var rows = db_query(db, \"SELECT * FROM messages ORDER BY rowid DESC LIMIT 50\", []);\n                return http_response(200, json_stringify(rows));\n            });\n            http_listen(server, \"0.0.0.0:8090\");\n        }\n    }\n}"},
{"instruction": "Erstelle einen Agenten, der eine Pipeline nutzt, um Log-Eintraege zu normalisieren, filtern und in eine DB zu schreiben.", "output": "agent LogProcessor {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var db_cap = DbAccess {};\n            var db = db_open(\"logs.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS logs (level TEXT, message TEXT)\", []);\n            var lines = fs_read_lines(\"raw.log\") or [];\n            var pipe = __varg_pipeline_new(\"log_pipe\");\n            __varg_pipeline_add_step(pipe, \"trim\", (input) => input.trim());\n            __varg_pipeline_add_step(pipe, \"normalize\", (input) => input.to_lower());\n            for line in lines {\n                if !line.trim().is_empty() {\n                    var processed = __varg_pipeline_run(pipe, line);\n                    var level = processed.starts_with(\"error\") ? \"ERROR\" : \"INFO\";\n                    db_execute(db, \"INSERT INTO logs (level, message) VALUES (?1, ?2)\", [level, processed]);\n                }\n            }\n        }\n    }\n}"},
{"instruction": "Baue einen Agenten, der per HTTP Daten abruft, in den Vector Store embeddet und per MCP bereitstellt.", "output": "agent IndexAndServe {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var llm = LlmAccess {};\n            var sys = SystemAccess {};\n            try {\n                var data = fetch(\"https://api.example.com/articles\", \"GET\")?;\n                var json = json_parse(data)?;\n                var articles = json_get_array(json, \"/articles\");\n                var store = __varg_vector_store_open(\"articles\");\n                for art in articles {\n                    var emb = __varg_embed(art);\n                    __varg_vector_store_upsert(store, art, emb, {});\n                }\n                var server = __varg_mcp_server_new(\"article_search\", \"1.0.0\");\n                __varg_mcp_server_register(server, \"search\", \"Search articles\", (args) => {\n                    var query = json_get(args, \"/query\");\n                    var emb = __varg_embed(query);\n                    var results = __varg_vector_store_search(store, emb, 3);\n                    return json_stringify(results);\n                });\n                __varg_mcp_server_run(server);\n            } catch err {\n                log_error($\"Failed: {err}\");\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle einen Agent, der den Self-Improver nutzt und bei Misserfolg die Strategie aendert.", "output": "agent RetryWithLearning {\n    public void Run() {\n        var si = __varg_self_improver_new(\"learner\", 10);\n        unsafe {\n            var net = NetworkAccess {};\n            var urls = [\"https://api.example.com/v1\", \"https://api.example.com/v2\", \"https://fallback.example.com\"];\n            for url in urls {\n                try {\n                    var resp = fetch(url, \"GET\")?;\n                    __varg_self_improver_record_success(si, $\"fetch_{url}\", \"Direct GET succeeded\");\n                    print $\"Success: {url}\";\n                    break;\n                } catch err {\n                    __varg_self_improver_record_failure(si, $\"fetch_{url}\", $\"{err}\");\n                    log_warn($\"Failed {url}, trying next\");\n                }\n            }\n            var stats = __varg_self_improver_stats(si);\n            print $\"Attempts: {stats[\"iterations\"]}, Success rate: {stats[\"success_rate\"]}\";\n        }\n    }\n}"},
{"instruction": "Baue eine Event-gesteuerte Architektur: Event Bus triggert Pipeline, Pipeline schreibt in DB.", "output": "agent EventDrivenApp {\n    public void Run() {\n        unsafe {\n            var db_cap = DbAccess {};\n            var db = db_open(\"events.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS processed (event TEXT, result TEXT)\", []);\n            var pipe = __varg_pipeline_new(\"event_processor\");\n            __varg_pipeline_add_step(pipe, \"validate\", (input) => {\n                if input.is_empty() {\n                    return \"INVALID\";\n                }\n                return input;\n            });\n            __varg_pipeline_add_step(pipe, \"transform\", (input) => input.to_upper());\n            var bus = __varg_event_bus_new(\"app\");\n            __varg_event_on(bus, \"data_received\", (data) => {\n                var result = __varg_pipeline_run(pipe, data[\"payload\"]);\n                db_execute(db, \"INSERT INTO processed (event, result) VALUES (?1, ?2)\", [\"data_received\", result]);\n                return result;\n            });\n            __varg_event_emit(bus, \"data_received\", {\"payload\": \"hello world\"});\n        }\n    }\n}"},
{"instruction": "Erstelle einen Agenten, der Dateien nach Erweiterung gruppiert und die Ergebnisse in JSON ausgibt.", "output": "agent FileGrouper {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var files = fs_read_dir(\"./src\") or [];\n            var groups = {};\n            for f in files {\n                var ext = path_extension(f);\n                if ext.is_empty() {\n                    ext = \"no_ext\";\n                }\n                if !groups.contains_key(ext) {\n                    groups[ext] = \"0\";\n                }\n                var count = parse_int(groups[ext]) or 0;\n                groups[ext] = $\"{count + 1}\";\n            }\n            for (ext, count) in groups {\n                print $\".{ext}: {count} files\";\n            }\n        }\n    }\n}"},
{"instruction": "Nutze Orchestrator und Tracing zusammen: traciere die Ausfuehrung paralleler Tasks.", "output": "agent TracedOrchestrator {\n    public void Run() {\n        var tracer = __varg_trace_start(\"parallel_runner\");\n        var span = __varg_trace_span(tracer, \"orchestration\");\n        var orch = __varg_orchestrator_new(\"traced_batch\");\n        __varg_orchestrator_add_task(orch, \"task_a\", \"alpha\");\n        __varg_orchestrator_add_task(orch, \"task_b\", \"beta\");\n        __varg_orchestrator_add_task(orch, \"task_c\", \"gamma\");\n        __varg_orchestrator_run_all(orch, (input) => {\n            return $\"{input}_done\";\n        });\n        var results = __varg_orchestrator_results(orch);\n        __varg_trace_set_attr(tracer, \"task_count\", $\"{results.len()}\");\n        for r in results {\n            __varg_trace_event(tracer, \"task_completed\", {\"id\": r[\"id\"], \"result\": r[\"result\"]});\n        }\n        __varg_trace_end(tracer, span);\n        print __varg_trace_export(tracer);\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der per HTTP einen JSON-Body empfaengt, validiert und in SQLite speichert.", "output": "agent ValidationServer {\n    public async void Run() {\n        unsafe {\n            var db_cap = DbAccess {};\n            var db = db_open(\"submissions.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS submissions (name TEXT, email TEXT)\", []);\n            var server = http_serve();\n            http_route(server, \"POST\", \"/submit\", (req) => {\n                var json = json_parse(req.body) or \"{}\";\n                var name = json_get(json, \"/name\");\n                var email = json_get(json, \"/email\");\n                if name.is_empty() {\n                    return http_response(400, \"{\\\"error\\\": \\\"name required\\\"}\");\n                }\n                if !email.contains(\"@\") {\n                    return http_response(400, \"{\\\"error\\\": \\\"invalid email\\\"}\");\n                }\n                db_execute(db, \"INSERT INTO submissions (name, email) VALUES (?1, ?2)\", [name, email]);\n                return http_response(201, \"{\\\"status\\\": \\\"created\\\"}\");\n            });\n            http_listen(server, \"0.0.0.0:3000\");\n        }\n    }\n}"},
