{"instruction": "Erstelle eine PDF-Datei mit Titel, mehreren Sektionen und dynamischem Text aus einer Datei.", "output": "agent DynamicPdfReport {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var content = fs_read(\"report_data.txt\") or \"No data available\";\n            var lines = content.split(\"\\n\");\n            var pdf = pdf_create(\"Dynamic Report\");\n            pdf_add_section(pdf, \"Overview\");\n            pdf_add_text(pdf, $\"Generated at: {time_format(time_millis(), \"%Y-%m-%d %H:%M\")}\");\n            pdf_add_section(pdf, \"Data\");\n            for line in lines {\n                if !line.trim().is_empty() {\n                    pdf_add_text(pdf, line);\n                }\n            }\n            pdf_save(pdf, \"dynamic_report.pdf\");\n            print \"PDF generated.\";\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der regelmaessig eine URL pollt und Aenderungen in einer Datei protokolliert.", "output": "agent UrlPoller {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var fs = FileAccess {};\n            var last_hash = \"\";\n            for i in 0..10 {\n                try {\n                    var content = fetch(\"https://api.example.com/status\", \"GET\")?;\n                    var current_hash = $\"{content.len()}\";\n                    if current_hash != last_hash {\n                        var ts = time_format(time_millis(), \"%H:%M:%S\");\n                        fs_append(\"changes.log\", $\"[{ts}] Change detected: {current_hash}\\n\")?;\n                        last_hash = current_hash;\n                    }\n                } catch err {\n                    log_warn($\"Poll failed: {err}\");\n                }\n            }\n        }\n    }\n}"},
{"instruction": "Nutze mehrere Worker-Agenten, die ueber on_message verschiedene Aufgaben erledigen.", "output": "agent FileWorker {\n    public void on_message(string msg, string[] args) {\n        if msg == \"read\" {\n            unsafe {\n                var fs = FileAccess {};\n                var content = fs_read(args[0]) or \"error\";\n                print $\"File content: {content.len()} chars\";\n            }\n        }\n    }\n}\n\nagent NetWorker {\n    public void on_message(string msg, string[] args) {\n        if msg == \"fetch\" {\n            unsafe {\n                var net = NetworkAccess {};\n                var resp = fetch(args[0], \"GET\") or \"error\";\n                print $\"Response: {resp.len()} chars\";\n            }\n        }\n    }\n}\n\nagent Coordinator {\n    public void Run() {\n        var fw = spawn FileWorker {};\n        var nw = spawn NetWorker {};\n        fw.send(\"read\", [\"config.json\"]);\n        nw.send(\"fetch\", [\"https://example.com\"]);\n    }\n}"},
{"instruction": "Implementiere einen Agenten, der JSON-Daten aus einer API liest und als CSV-Datei speichert.", "output": "agent JsonToCsv {\n    public void Convert(string url, string output_path, NetworkAccess net, FileAccess fs) {\n        var data = fetch(url, \"GET\")?;\n        var json = json_parse(data)?;\n        var items = json_get_array(json, \"/items\");\n        var csv = \"name,value\\n\";\n        for item in items {\n            var parsed = json_parse(item)?;\n            var name = json_get(parsed, \"/name\");\n            var value = json_get(parsed, \"/value\");\n            csv = csv + $\"{name},{value}\\n\";\n        }\n        fs_write(output_path, csv)?;\n    }\n\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var fs = FileAccess {};\n            try {\n                self.Convert(\"https://api.example.com/export\", \"output.csv\", net, fs);\n                print \"CSV exported.\";\n            } catch err {\n                log_error($\"Export failed: {err}\");\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle einen Health-Check-Agenten, der mehrere URLs testet und den Status in einer Map sammelt.", "output": "agent HealthChecker {\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            var urls = [\"https://service1.local/health\", \"https://service2.local/health\", \"https://service3.local/health\"];\n            var results = {};\n            for url in urls {\n                try {\n                    var resp = fetch(url, \"GET\")?;\n                    results[url] = \"healthy\";\n                } catch err {\n                    results[url] = $\"unhealthy: {err}\";\n                }\n            }\n            for (url, status) in results {\n                print $\"{url} -> {status}\";\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle eine Pipeline, die Text aus einer Datei liest, Woerter zaehlt und das Ergebnis in SQLite speichert.", "output": "agent WordCountPipeline {\n    public void Run() {\n        unsafe {\n            var fs = FileAccess {};\n            var db_cap = DbAccess {};\n            var db = db_open(\"analytics.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS word_counts (file TEXT, count INTEGER)\", []);\n            var files = fs_read_dir(\"./texts\") or [];\n            for f in files {\n                var content = fs_read(f) or \"\";\n                var words = content.split(\" \");\n                var count = words.filter((w) => !w.trim().is_empty()).len();\n                db_execute(db, \"INSERT INTO word_counts (file, count) VALUES (?1, ?2)\", [f, $\"{count}\"]);\n                print $\"{f}: {count} words\";\n            }\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der Environment-Variablen liest und eine entsprechende Konfiguration aufbaut.", "output": "agent EnvConfig {\n    public void Run() {\n        var db_host = env(\"DB_HOST\") or \"localhost\";\n        var db_port = env(\"DB_PORT\") or \"5432\";\n        var db_name = env(\"DB_NAME\") or \"vargdb\";\n        var debug = env(\"DEBUG\") or \"false\";\n        print $\"Database: {db_host}:{db_port}/{db_name}\";\n        if debug == \"true\" {\n            log_debug(\"Debug mode enabled\");\n        }\n    }\n}"},
{"instruction": "Nutze den Event Bus, um auf Datei-Aenderungen zu reagieren und einen Rebuild zu triggern.", "output": "agent FileWatcher {\n    public void Run() {\n        var bus = __varg_event_bus_new(\"watcher\");\n        __varg_event_on(bus, \"file_changed\", (data) => {\n            var file = data[\"path\"];\n            print $\"File changed: {file}\";\n            unsafe {\n                var sys = SystemAccess {};\n                var output = exec(\"vargc\", [\"build\", file]) or \"build failed\";\n                print output;\n            }\n            return \"rebuilt\";\n        });\n        __varg_event_emit(bus, \"file_changed\", {\"path\": \"main.varg\"});\n    }\n}"},
{"instruction": "Erstelle einen MCP-Server, der eine SQLite-Datenbank als Tool bereitstellt.", "output": "agent DbMcpServer {\n    public void Run() {\n        unsafe {\n            var sys = SystemAccess {};\n            var db_cap = DbAccess {};\n            var db = db_open(\"shared.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS notes (id INTEGER PRIMARY KEY, text TEXT)\", []);\n            var server = __varg_mcp_server_new(\"db_tools\", \"1.0.0\");\n            __varg_mcp_server_register(server, \"add_note\", \"Add a note\", (args) => {\n                var text = json_get(args, \"/text\");\n                db_execute(db, \"INSERT INTO notes (text) VALUES (?1)\", [text]);\n                return \"Note added\";\n            });\n            __varg_mcp_server_register(server, \"list_notes\", \"List all notes\", (args) => {\n                var rows = db_query(db, \"SELECT * FROM notes\", []);\n                return json_stringify(rows);\n            });\n            __varg_mcp_server_run(server);\n        }\n    }\n}"},
{"instruction": "Schreibe einen Agenten, der eine HTTP API abfragt, die Antwort cached und bei erneutem Aufruf den Cache nutzt.", "output": "agent CachingFetcher {\n    map<string, string> cache;\n\n    public string CachedFetch(string url, NetworkAccess net) {\n        if self.cache.contains_key(url) {\n            log_info($\"Cache hit: {url}\");\n            return self.cache[url];\n        }\n        var resp = fetch(url, \"GET\")?;\n        self.cache[url] = resp;\n        return resp;\n    }\n\n    public void Run() {\n        unsafe {\n            var net = NetworkAccess {};\n            try {\n                var r1 = self.CachedFetch(\"https://api.example.com/data\", net);\n                var r2 = self.CachedFetch(\"https://api.example.com/data\", net);\n                print $\"First: {r1.len()}, Second (cached): {r2.len()}\";\n            } catch err {\n                print $\"Error: {err}\";\n            }\n        }\n    }\n}"},
{"instruction": "Erstelle einen Agenten, der ein einfaches Token-basiertes Auth-System implementiert.", "output": "agent AuthServer {\n    public async void Run() {\n        unsafe {\n            var db_cap = DbAccess {};\n            var db = db_open(\"auth.db\");\n            db_execute(db, \"CREATE TABLE IF NOT EXISTS tokens (token TEXT PRIMARY KEY, user TEXT)\", []);\n            var server = http_serve();\n            http_route(server, \"POST\", \"/login\", (req) => {\n                var json = json_parse(req.body) or \"{}\";\n                var user = json_get(json, \"/username\");\n                var token = base64_encode($\"{user}:{time_millis()}\");\n                db_execute(db, \"INSERT INTO tokens (token, user) VALUES (?1, ?2)\", [token, user]);\n                return http_response(200, $\"{\\\"token\\\": \\\"{token}\\\"}\");\n            });\n            http_route(server, \"GET\", \"/protected\", (req) => {\n                var token = req.headers[\"Authorization\"] or \"\";\n                var rows = db_query(db, \"SELECT user FROM tokens WHERE token = ?1\", [token]);\n                if rows.is_empty() {\n                    return http_response(401, \"{\\\"error\\\": \\\"unauthorized\\\"}\");\n                }\n                return http_response(200, $\"{\\\"user\\\": \\\"{rows[0][\"user\"]}\\\"}\");\n            });\n            http_listen(server, \"0.0.0.0:3000\");\n        }\n    }\n}"},
